class Solution:
    def minimumBuckets(self, hamsters):
        dots = [i for i, c in enumerate(hamsters) if c == '.']
        hs = [i for i, c in enumerate(hamsters) if c == 'H']
        m = len(dots)
        best = -1
        for mask in range(1 << m):
            chosen = set(dots[j] for j in range(m) if mask & (1 << j))
            feasible = True
            for h in hs:
                if (h - 1) not in chosen and (h + 1) not in chosen:
                    feasible = False
                    break
            if feasible:
                cnt = bin(mask).count('1')
                if best == -1 or cnt < best:
                    best = cnt
        return best

