class Solution:
    def minimumBuckets(self, hamsters):
        s = list(hamsters)
        n = len(s)
        for i in range(n):
            if s[i] == 'H':
                if i > 0 and s[i - 1] == 'B':
                    continue
                if i + 1 < n and s[i + 1] == '.':
                    s[i + 1] = 'B'
                elif i > 0 and s[i - 1] == '.':
                    s[i - 1] = 'B'
                else:
                    return -1
        return s.count('B')

