var minimumBuckets = function(hamsters) {
    const s = hamsters.split('');
    const n = s.length;
    for (let i = 0; i < n; i++) {
        if (s[i] === 'H') {
            if (i > 0 && s[i - 1] === 'B') continue;
            if (i + 1 < n && s[i + 1] === '.') {
                s[i + 1] = 'B';
            } else if (i > 0 && s[i - 1] === '.') {
                s[i - 1] = 'B';
            } else {
                return -1;
            }
        }
    }
    return s.filter(c => c === 'B').length;
};
